import{_ as a,o as t,c as p,j as e,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"终焉射手","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/4.A级/终焉射手.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/4.A级/终焉射手.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/4.A级/终焉射手.md"};function d(i,r,l,_,c,h){return t(),p("div",null,[...r[0]||(r[0]=[e("h1",{id:"终焉射手",tabindex:"-1"},[s("终焉射手 "),e("a",{class:"header-anchor",href:"#终焉射手","aria-label":'Permalink to "终焉射手"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),n('<h1 id="终焉射手-1" tabindex="-1">终焉射手 <a class="header-anchor" href="#终焉射手-1" aria-label="Permalink to &quot;终焉射手&quot;">​</a></h1><p>IDEA-E-012-『终焉射手』<br> 科技本质<br> A+4000<br> 分类：狙击枪<br> 武器伤害：29L+3<br> 武器特性：【双手】【高速5】【破甲3】【能量武器】<br> 伤害类型：光能/见下<br> 射程：200米/见下<br> 装弹量：6+1/见下<br> 体积：20<br> 描述：IDEA异能定制武装系列第三件实际产品，积累了上一次的成功经验，成功复刻并将异能完美保存为武装的、系列第一把远程武装，代号E-012，武装名称为——『终焉射手』。<br> 该武装具有极其庞大的枪身，枪身全长8米，宽2.45米，高4米，以特质的魔锻化散热黑金进行全枪身主要结构的锻造，与内置的极其精密的散热系统共同作为主要组成部分，搭载了除主要发射舱外的另外6发备弹存储舱，占据了7米长度的巨大枪管分为蓄能舱与释能舱两部分，射击前，储存了异能全力释放的特殊弹药将填充在蓄能舱中进行激活，并最终穿过用于限定射击方向巨型枪管发射出去，多余的热量通过散热机构从枪身两侧各3处共6个释能舱口排放出深蓝色的高温烟雾。</p><p>后方长一米的发射舱则是操作者的持用位置，操作者须在发射前主动展开固定脚架，在武装内置的类人脑智能生命系统，异灵（Sprite）『自由射手（Der Freischütz）』的辅助下，通过内置的战场追踪系统将你敏感范围内的所有地形进行扫描，同时以4D战术建模进行实时塑造直观展现，如瞄准镜般在枪身遮挡视野的前提下依然准确地为视觉感知提供瞄准能力。</p><p>该武装无法获得任何形式的【无限子弹】特性，不会被任何能力降低装弹动作，并且无法以任何形式提高连射等级。</p><p>购买该武装后会配备一发体积为8的专属弹药：『自由魔弹』，这是一种半径1.5米，长3.2米的圆柱形特供弹药，使用后如发射消耗品子弹般永久失去。</p><p>该武装的枪身从本质上来说是在模仿曾经该异能使用者所用的枪管，并添加限制以压制异灵的自我意志，而异能本身则以子弹的方式进行储存与随取随用，这也是为什么武器额外配备了弹舱用于储存备弹；由于该武装的异能子弹制造极其繁琐与珍贵，必须储存在具有异能『魔弹射手（Der Freischütz）』的器具当中，所以，『自由魔弹』只能装填在该武装当中同时存取，无法单独存储，如果脱离了『终焉射手』武装超过十秒，内部储存的异能就会彻底失效，所以也无法将其储存在任何独立的储存空间或者异空间中试图保存，任何类似的行为都会使得子弹失效。</p><p>该武器的最多装弹量为1发，备弹6发，每次发射前必须以移动动作激活瞄准。</p><p>若要额外购买子弹，每发价格为16000积分。</p><p>特殊的，该武器内填入蓄能舱的1发子弹会视为武器本身，仅计算武器本身的评分，额外购买的至多6发备弹则分别单独以一次性消耗品进行计算。</p><p>该武器搭载了名为『魔弹射手』的强攻型异能，以该武器发射『自由魔弹』时，攻击将转为范围光炮攻击，光炮的射程距离等同于武器攻击射程，光炮的半径为攻击射程的四分之一米(上限不超过200米)，由于该异能的火力已经被限制了许多，实在没办法在如此高能的输出下对敌我进行分辨，所以该武器进行的攻击将无视敌我同时造成伤害，视为【能量武器】，额外具有【高速8】。</p><p>以该武装进行攻击前，必须以一个移动动作进行蓄能装填，哪怕武器当中已经装填了子弹也必须以此进行激活，该步骤非常精准繁琐，需要异灵『魔弹射手（Der Freischütz）』的紧密配合，将瞄准模型与现实进行同步迭代，将填入蓄能舱中的『自由魔弹』激活的同时，这次武器的射程提升为自身的敏感范围半径*1米，并额外具有【高速5】。</p><p>激活后，魔弹将正式发射，深蓝色的高温激光将瞬间吞噬眼前的一切，仅针对这次攻击，武器伤害额外提升30L，自身的敏感范围额外提升一倍，加骰提升一级(至多8加骰)，那之后，对射程内的所有事物造成光能/燃烧取优的严重伤害，正常进行破防计算的同时，这次攻击具有A级诅咒来源的无视偏斜防御能力与【超级贯穿】特性，附带伤害等量的燃烧异常点数，强韧豁免；除此之外，以这次攻击伤害作为dc，所有承受伤害者额外以强韧豁免，若豁免失败则瞬间被高能输出轰碎汽化，这是一个A级创伤来源的A级即死效果，任何因此次攻击死亡的敌人将无法以S级及更低等级的能力进行复活。</p><p>射击之后，武器需要进行数秒的释能行为才能进行下一次射击，这意味着通常情况下，该武器无法在单回合内多次进行攻击。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const A=a(o,[["render",d]]);export{f as __pageData,A as default};
